code.C:
#include <stdio.h>
#include <math.h>
int main(){
    double temperature = 25.5;
    double kelvin = temperature + 273.15;
    kelvin = floor(kelvin*10 + 0.5)/10.0;
    printf("Celsius - %.1f  Kelvin - %.1f\n", temperature, kelvin);
    return 0;
}

